import React, { useState, useEffect } from 'react';
import { MapPin, History, BrainCircuit, Navigation, Activity, Loader2, Clock, CheckCircle2, BarChart3, LogIn, Info, Mail, LayoutDashboard } from 'lucide-react';

function App() {
  const [view, setView] = useState("login"); // View states: login, dashboard, about, contact
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [user, setUser] = useState(null);
  const [history, setHistory] = useState("");
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState(null);
  const [error, setError] = useState(null);
  const [logs, setLogs] = useState([]);

  useEffect(() => {
    const savedLogs = localStorage.getItem('st_recent_logs');
    if (savedLogs) setLogs(JSON.parse(savedLogs));
    const session = localStorage.getItem('user_session');
    if (session) { setUser(session); setView("dashboard"); }
  }, []);

  const handleLogin = async (e) => {
    e.preventDefault();
    try {
      const res = await fetch('http://localhost:8000/api/login', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ email, password })
      });
      if (!res.ok) throw new Error("Unauthorized Credentials Provided");
      const data = await res.json();
      setUser(data.user);
      localStorage.setItem('user_session', data.user);
      setView("dashboard");
    } catch (err) { alert(err.message); }
  };

  const handleLogout = () => {
    localStorage.removeItem('user_session');
    setUser(null);
    setView("login");
  };

  const handlePredict = async () => {
    if (!history) return;
    setLoading(true); setError(null);
    try {
      const historyArray = history.split(',').map(num => parseInt(num.trim()));
      const response = await fetch('http://localhost:8000/predict', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ history: historyArray })
      });
      const data = await response.json();
      setResult(data);
      const newLog = { id: Date.now(), input: history, prediction: data.recommendations[0].name, time: data.current_time };
      const updatedLogs = [newLog, ...logs].slice(0, 6);
      setLogs(updatedLogs);
      localStorage.setItem('st_recent_logs', JSON.stringify(updatedLogs));
    } catch (err) { setError(err.message); } finally { setLoading(false); }
  };

  return (
    <div className="min-h-screen bg-slate-50 flex">
      {/* 1. Global Navigation Sidebar */}
      <div className="w-72 bg-slate-900 text-white p-6 hidden md:flex flex-col border-r border-slate-800">
        <div className="flex items-center gap-3 mb-10">
          <BrainCircuit className="text-blue-400" size={32} />
          <h1 className="font-bold text-xl tracking-tight">ST-HybridRec</h1>
        </div>

        {user && (
          <nav className="space-y-2 mb-6">
            <button onClick={() => setView("dashboard")} className={`w-full flex items-center gap-3 p-3 rounded-xl text-sm transition-all ${view === 'dashboard' ? 'bg-blue-600 text-white font-bold' : 'text-slate-400 hover:bg-slate-800'}`}>
              <LayoutDashboard size={18} /> Dashboard Analysis
            </button>
            <button onClick={() => setView("about")} className={`w-full flex items-center gap-3 p-3 rounded-xl text-sm transition-all ${view === 'about' ? 'bg-blue-600 text-white font-bold' : 'text-slate-400 hover:bg-slate-800'}`}>
              <Info size={18} /> About System
            </button>
            <button onClick={() => setView("contact")} className={`w-full flex items-center gap-3 p-3 rounded-xl text-sm transition-all ${view === 'contact' ? 'bg-blue-600 text-white font-bold' : 'text-slate-400 hover:bg-slate-800'}`}>
              <Mail size={18} /> Support Desk
            </button>
          </nav>
        )}

        {view === "dashboard" && user && (
          <div className="flex-1 overflow-y-auto">
            <h3 className="text-xs font-bold text-slate-500 uppercase tracking-widest mb-4 flex items-center gap-2"><History size={14} /> Recent Activity</h3>
            <div className="space-y-3">
              {logs.map(log => (
                <div key={log.id} className="bg-slate-800/40 p-3 rounded-xl border border-slate-700/50">
                  <div className="flex justify-between text-[10px] text-blue-400 font-bold"><span>Trace: [{log.input}]</span><span>{log.time}</span></div>
                  <p className="text-xs text-slate-300 truncate">➜ {log.prediction}</p>
                </div>
              ))}
            </div>
          </div>
        )}

        {user && (
          <div className="mt-auto pt-4 border-t border-slate-800 flex flex-col gap-2">
            <p className="text-xs text-slate-400 truncate">Active: {user}</p>
            <button onClick={handleLogout} className="text-xs text-red-400 hover:text-red-300 text-left">Logout Session</button>
          </div>
        )}
      </div>

      {/* 2. Main Canvas Switch Panel */}
      <main className="flex-1 p-8 overflow-y-auto flex flex-col justify-center">
        
        {/* VIEW A: LOGIN SCREEN */}
        {view === "login" && (
          <div className="max-w-md w-full mx-auto bg-white p-8 rounded-3xl shadow-xl border border-slate-200">
            <div className="text-center mb-8">
              <BrainCircuit className="text-blue-600 mx-auto mb-3" size={44} />
              <h2 className="text-2xl font-black text-slate-800">Branch Gateway Sign-In</h2>
              <p className="text-slate-400 text-sm mt-1">AI & Data Science Spatial Verification Engine</p>
            </div>
            <form onSubmit={handleLogin} className="space-y-4">
              <div>
                <label className="text-xs font-bold text-slate-500 uppercase">Institutional Email</label>
                <input type="email" value={email} onChange={e => setEmail(e.target.value)} required className="w-full px-4 py-3 border border-slate-200 rounded-xl mt-1 focus:ring-2 focus:ring-blue-500 outline-none" placeholder="admin@mmit.edu.in" />
              </div>
              <div>
                <label className="text-xs font-bold text-slate-500 uppercase">Security Passcode</label>
                <input type="password" value={password} onChange={e => setPassword(e.target.value)} required className="w-full px-4 py-3 border border-slate-200 rounded-xl mt-1 focus:ring-2 focus:ring-blue-500 outline-none" placeholder="••••••••" />
              </div>
              <button type="submit" className="w-full bg-blue-600 hover:bg-blue-700 text-white font-bold py-4 rounded-xl shadow-lg flex items-center justify-center gap-2 transition-all">
                <LogIn size={18} /> Verify and Launch Engine
              </button>
            </form>
          </div>
        )}

        {/* VIEW B: MAIN RECHYBRID INFERENCE DASHBOARD */}
        {view === "dashboard" && (
          <div className="h-full flex flex-col justify-start animate-in fade-in duration-300">
            <header className="flex justify-between items-center mb-8">
              <div><h2 className="text-2xl font-bold text-slate-800">Spatial-Temporal Analysis</h2><p className="text-slate-500 text-sm">Indian Regional Infrastructure Vectors (GCN + LSTM)</p></div>
              <div className="text-xs font-mono bg-green-100 text-green-700 px-3 py-1 rounded-full border border-green-200 flex items-center gap-2"><div className="h-2 w-2 bg-green-500 rounded-full animate-pulse"></div> Local Node: Deployed</div>
            </header>
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
              <div className="lg:col-span-1 space-y-6">
                <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
                  <label className="block text-sm font-semibold text-slate-700 mb-2">Visit History Trace</label>
                  <input type="text" value={history} onChange={(e) => setHistory(e.target.value)} placeholder="e.g. 0, 1, 2" className="w-full px-4 py-3 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none transition-all"/>
                  <button onClick={handlePredict} disabled={loading || !history} className="w-full mt-6 bg-blue-600 hover:bg-blue-700 text-white font-bold py-4 rounded-xl shadow-lg disabled:bg-slate-300">
                    {loading ? <Loader2 className="animate-spin m-auto" /> : "Run Hybrid Inference"}
                  </button>
                </div>
                {result && result.metrics && (
                  <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
                    <h3 className="text-xs font-bold text-slate-500 uppercase tracking-widest mb-4 flex items-center gap-2"><BarChart3 size={14} className="text-blue-500" /> Performance Matrix</h3>
                    <div className="grid grid-cols-2 gap-3">
                      {[["Accuracy", result.metrics.accuracy], ["F1-Score", result.metrics.f1_score], ["Precision", result.metrics.precision], ["Recall", result.metrics.recall]].map(([label, val]) => (
                        <div key={label} className="p-3 bg-slate-50 rounded-xl border border-slate-100 text-center">
                          <p className="text-[9px] text-slate-400 font-bold uppercase">{label}</p>
                          <p className="text-base font-black text-slate-700">{(val * 100).toFixed(1)}%</p>
                        </div>
                      ))}
                    </div>
                  </div>
                )}
              </div>
              <div className="lg:col-span-2 space-y-6">
                {result && (
                  <>
                    <div className="bg-white border-l-4 border-blue-500 rounded-r-2xl p-5 shadow-sm flex justify-between items-center">
                      <div><p className="text-[10px] font-bold text-blue-600 uppercase mb-1">Semantic Reasoning</p><div className="flex items-center gap-2 text-slate-700 font-semibold"><Clock size={16} />{result.reasoning}</div></div>
                      <div className="text-right"><p className="text-[10px] font-bold text-slate-400 uppercase mb-1">Traceability</p><code className="bg-slate-100 px-3 py-1 rounded-lg text-slate-600 font-bold text-xs">[{result.input_echo.join(", ")}]</code></div>
                    </div>
                    <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                      {result.recommendations.map((poi, i) => (
                        <div key={i} className={`relative bg-white border rounded-2xl p-6 transition-all ${i === 0 ? 'border-blue-500 shadow-md' : 'border-slate-200'}`}>
                          <div className={`absolute top-0 right-0 px-3 py-1 rounded-bl-xl text-[9px] font-black ${i === 0 ? 'bg-blue-600 text-white' : 'bg-slate-100 text-slate-500'}`}>RANK #{i+1}</div>
                          <div className="mt-4"><span className="text-[10px] bg-slate-100 px-2 py-0.5 rounded-full font-bold uppercase text-slate-500">{poi.category}</span><h3 className="text-lg font-bold text-slate-800 mt-2 truncate">{poi.name}</h3></div>
                          <div className="mt-6"><div className="flex justify-between mb-2"><span className="text-[10px] text-slate-400 font-bold uppercase">Confidence</span><span>{(poi.confidence * 100).toFixed(0)}%</span></div>
                          <div className="bg-slate-100 h-1.5 rounded-full overflow-hidden"><div className="bg-blue-600 h-full" style={{ width: `${poi.confidence * 100}%` }}></div></div></div>
                        </div>
                      ))}
                    </div>
                  </>
                )}
              </div>
            </div>
          </div>
        )}

        {/* VIEW C: ABOUT US SCREEN */}
        {view === "about" && (
          <div className="max-w-2xl bg-white p-8 rounded-3xl shadow-sm border border-slate-200 mx-auto animate-in fade-in duration-300">
            <h2 className="text-2xl font-black text-slate-800 mb-4">About the System</h2>
            <p className="text-slate-600 text-sm leading-relaxed mb-4">
              This system represents a Next-Generation Spatial-Temporal Recommendation engine engineered for institutional urban mapping. By exploiting <strong>Graph Convolutional Networks (GCN)</strong>, the architecture learns geographical constraints and physical proximity maps across local configurations.
            </p>
            <p className="text-slate-600 text-sm leading-relaxed mb-6">
              Simultaneously, a <strong>Long Short-Term Memory (LSTM)</strong> pipeline processes historical sequence vectors. When fused with temporal context blocks via mathematical concatenation, the platform calculates predictive trajectories with high structural confidence.
            </p>
            <div className="p-4 bg-blue-50 rounded-xl border border-blue-100 text-xs text-blue-700 font-medium">
              Affiliation: Department of Artificial Intelligence & Data Science (AI & DS)
            </div>
          </div>
        )}

        {/* VIEW D: CONTACT US SCREEN */}
        {view === "contact" && (
          <div className="max-w-xl bg-white p-8 rounded-3xl shadow-sm border border-slate-200 mx-auto animate-in fade-in duration-300 text-center">
            <Mail className="text-blue-600 mx-auto mb-4" size={48} />
            <h2 className="text-2xl font-black text-slate-800 mb-2">Technical Support Desk</h2>
            <p className="text-slate-500 text-sm mb-6">Encountering configuration bugs or compilation hitches? Drop an execution report to our lab gateway.</p>
            <div className="space-y-3 max-w-xs mx-auto text-sm text-slate-700">
              <div className="p-3 bg-slate-50 rounded-xl border border-slate-200 font-semibold">📍 MMIT Campus, Pune, India</div>
              <div className="p-3 bg-slate-50 rounded-xl border border-slate-200 font-mono">📧 support@mmit.edu.in</div>
            </div>
          </div>
        )}

      </main>
    </div>
  );
}

export default App;
